Here's a modern MSTest test class for your `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(HttpMessageHandler handler)
        => new(new HttpClient(handler));

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello world"),
        });
        var fetcher = CreateFetcher(handler);

        // Act
        var result = await fetcher.FetchAsync("https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing", _testContext.CancellationToken));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange — handler that delays long enough for cancellation to fire
        var handler = new FakeHandler(async (_, ct) =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = CreateFetcher(handler);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        // Act & Assert
        await Assert.ThrowsAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_PassesUrlToHandler()
    {
        // Arrange
        Uri? capturedUri = null;
        var handler = new FakeHandler((request, _) =>
        {
            capturedUri = request.RequestUri;
            return Task.FromResult(new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("ok"),
            });
        });
        var fetcher = CreateFetcher(handler);

        // Act
        await fetcher.FetchAsync("https://example.com/data", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual(new Uri("https://example.com/data"), capturedUri);
    }

    /// <summary>Minimal test double for HttpMessageHandler.</summary>
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> _send;

        public FakeHandler(HttpResponseMessage canned)
            : this((_, _) => Task.FromResult(canned)) { }

        public FakeHandler(Func<HttpRequestMessage, CancellationToken, Task<HttpResponseMessage>> send)
            => _send = send;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _send(request, cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Sealed class** | `public sealed class` — better perf & design clarity |
| **TestContext via ctor** | Constructor injection (MSTest 3.6+) |
| **Async + Timeout** | `[Timeout(5000)]` + pass `_testContext.CancellationToken` so the test is cancelled on timeout |
| **Cancellation testing** | Separate `CancellationTokenSource` with short delay to verify the token propagates |
| **Exception assertions** | `ThrowsExactlyAsync` for exact type; `ThrowsAsync` when derived types are acceptable (e.g., `TaskCanceledException` derives from `OperationCanceledException`) |
| **No mocking library** | Lightweight `FakeHandler` keeps dependencies minimal |

The `[Timeout]` attribute auto-cancels `TestContext.CancellationToken` when exceeded, so always forward it into your async calls to get clean timeout behavior.
